interface ProductCardProps{
    image: string,
    header: string,
    descirption: string,
    button1Url: string,
    button2Url:string
}

const handleCLick = (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();
    const data = new FormData(event.currentTarget);
    console.log({
      email: data.get('email'),
      password: data.get('password'),
